-- 2026-06-04 — Vendor logos for the Business Review Slide 10 auto-pull
--
-- Five PVP-program vendor logos uploaded into the public.deck_gallery
-- shared image library. Once these rows exist, gallerySrc({vendorId:VID})
-- returns the data_url and the BR Slide 10 vendor card auto-renders the
-- logo for every truck stop that has the vendor enrolled in VP_ENROLL.
--
-- Idempotent: ON CONFLICT (id) DO UPDATE — re-running replaces the
-- existing row in place with the latest data_url + updated_at.

BEGIN;

INSERT INTO public.deck_gallery (id, slot_key, label, category, vendor_id, data_url, notes, updated_at) VALUES
  ('g_vendor_V00036_logo', 'logo', 'DAS logo', 'vendor', 'V00036', 'data:image/jpeg;base64,', 'Uploaded 2026-06-04 via add_vendor_logos.py — 19343 bytes source', now()),
  ('g_vendor_V00010_logo', 'logo', 'Sysco logo', 'vendor', 'V00010', 'data:image/jpeg;base64,', 'Uploaded 2026-06-04 via add_vendor_logos.py — 35383 bytes source', now()),
  ('g_vendor_V00005_logo', 'logo', 'All Over Media logo', 'vendor', 'V00005', 'data:image/png;base64,', 'Uploaded 2026-06-04 via add_vendor_logos.py — 34917 bytes source', now()),
  ('g_vendor_V00022_logo', 'logo', 'Lynco logo', 'vendor', 'V00022', 'data:image/jpeg;base64,', 'Uploaded 2026-06-04 via add_vendor_logos.py — 8293 bytes source', now()),
  ('g_vendor_V00033_logo', 'logo', 'Coca-Cola CCNA logo', 'vendor', 'V00033', 'data:image/png;base64,', 'Uploaded 2026-06-04 via add_vendor_logos.py — 277027 bytes source', now())
ON CONFLICT (id) DO UPDATE SET
  data_url   = EXCLUDED.data_url,
  label      = EXCLUDED.label,
  category   = EXCLUDED.category,
  vendor_id  = EXCLUDED.vendor_id,
  slot_key   = EXCLUDED.slot_key,
  notes      = EXCLUDED.notes,
  updated_at = EXCLUDED.updated_at;

COMMIT;

